+                message: messageWithAttachments,
+                sessionId,
+                thinking: p.thinking,
+                deliver: p.deliver,
+                timeout: Math.ceil(timeoutMs / 1000).toString(),
+                surface: `Node(${nodeId})`,
+                abortSignal: abortController.signal,
+              },
+              defaultRuntime,
+              ctx.deps,
+            );
+            const payload = {
+              runId: clientRunId,
+              status: "ok" as const,
+            };
+            ctx.dedupe.set(`chat:${clientRunId}`, {
+              ts: Date.now(),
+              ok: true,
+              payload,
+            });
+            return { ok: true, payloadJSON: JSON.stringify(payload) };
+          } catch (err) {
+            const error = errorShape(ErrorCodes.UNAVAILABLE, String(err));
+            const payload = {
+              runId: clientRunId,
+              status: "error" as const,
+              summary: String(err),
+            };
+            ctx.dedupe.set(`chat:${clientRunId}`, {
+              ts: Date.now(),
+              ok: false,
+              payload,
+              error,
+            });
+            return {
+              ok: false,
+              error: error ?? {
+                code: ErrorCodes.UNAVAILABLE,
+                message: String(err),
+              },
+            };
+          } finally {
+            ctx.chatAbortControllers.delete(clientRunId);
+          }
+        }
+        default:
+          return {
+            ok: false,
+            error: {
+              code: "FORBIDDEN",
+              message: "Method not allowed",
+              details: { method },
+            },
+          };
+      }
+    } catch (err) {
+      return {
+        ok: false,
+        error: { code: ErrorCodes.INVALID_REQUEST, message: String(err) },
+      };
+    }
+  };
+
+  const handleBridgeEvent = async (
+    nodeId: string,
+    evt: { event: string; payloadJSON?: string | null },
+  ) => {
+    switch (evt.event) {
+      case "voice.transcript": {
+        if (!evt.payloadJSON) return;
+        let payload: unknown;
+        try {
+          payload = JSON.parse(evt.payloadJSON) as unknown;
+        } catch {
+          return;
+        }
+        const obj =
+          typeof payload === "object" && payload !== null
+            ? (payload as Record<string, unknown>)
+            : {};
+        const text = typeof obj.text === "string" ? obj.text.trim() : "";
+        if (!text) return;
+        if (text.length > 20_000) return;
+        const sessionKeyRaw =
+          typeof obj.sessionKey === "string" ? obj.sessionKey.trim() : "";
+        const mainKey =
+          (loadConfig().session?.mainKey ?? "main").trim() || "main";
+        const sessionKey = sessionKeyRaw.length > 0 ? sessionKeyRaw : mainKey;
+        const { storePath, store, entry } = loadSessionEntry(sessionKey);
+        const now = Date.now();
+        const sessionId = entry?.sessionId ?? randomUUID();
+        store[sessionKey] = {
+          sessionId,
+          updatedAt: now,
+          thinkingLevel: entry?.thinkingLevel,
+          verboseLevel: entry?.verboseLevel,
+          systemSent: entry?.systemSent,
+          lastChannel: entry?.lastChannel,
+          lastTo: entry?.lastTo,
+        };
+        if (storePath) {
+          await saveSessionStore(storePath, store);
+        }
